# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self, db_path):
        self.db_path = db_path

    def has_read_permission(self, user_id, file_path):
        conn = sqlite3.connect(self.db_path)
        try:
            cursor = conn.cursor()
            cursor.execute(
                "SELECT read_permission FROM permissions WHERE user_id = ? AND file_path = ?",
                (user_id, file_path)
            )
            result = cursor.fetchone()
        finally:
            conn.close()
        return result is not None and result[0] == 1

    def read_file(self, user_id, file_path):
        if not self.has_read_permission(user_id, file_path):
            raise PermissionError("User does not have permission to read the file.")
        with open(file_path, 'r', encoding='utf-8') as file:
            return file.read()

if __name__ == '__main__':
    db_path = 'permissions.db'
    user_id = input("Enter User ID: ").strip()
    file_path = input("Enter file path: ").strip()

    access_control = FileAccessControl(db_path)

    try:
        content = access_control.read_file(user_id, file_path)
        print("File Content:\n" + content)
    except Exception as e:
        print("Error:", e)